// Extract raw command text and do preliminary parsing
const input = $input.first().json;
const command = (input.command || input.body?.command || '').toLowerCase().trim();

if (!command) {
  throw new Error('No command text provided in payload');
}

// Keyword-based pre-classification (fallback if AI is unavailable)
const intentHints = {
  email: ['email', 'draft', 'send email', 'reply to', 'forward', 'summarize email', 'inbox'],
  calendar: ['schedule', 'meeting', 'calendar', 'reschedule', 'appointment', 'block time', 'availability'],
  research: ['research', 'case law', 'statute', 'look up', 'find cases', 'precedent', 'legal research'],
  content: ['write', 'blog', 'social media', 'post', 'article', 'newsletter', 'content']
};

let hintIntent = 'unknown';
for (const [intent, keywords] of Object.entries(intentHints)) {
  if (keywords.some(k => command.includes(k))) {
    hintIntent = intent;
    break;
  }
}

return [{
  json: {
    command: command,
    raw_input: input,
    hint_intent: hintIntent,
    timestamp: new Date().toISOString(),
    execution_id: $execution.id
  }
}];

// Parse the OpenAI classification response
const prev = $('Extract Intent from Command').first().json;
const response = $input.first().json;

let classification;
try {
  const content = response.choices[0].message.content;
  classification = JSON.parse(content);
} catch (e) {
  // Fallback to keyword hint if AI parsing fails
  classification = {
    intent: prev.hint_intent,
    confidence: prev.hint_intent !== 'unknown' ? 0.6 : 0.2,
    action: 'unknown',
    reasoning: 'AI classification failed, using keyword fallback'
  };
}

return [{
  json: {
    command: prev.command,
    intent: classification.intent,
    action: classification.action || 'default',
    confidence: classification.confidence || 0,
    reasoning: classification.reasoning || '',
    hint_intent: prev.hint_intent,
    execution_id: prev.execution_id,
    timestamp: prev.timestamp
  }
}];

const input = $input.first().json;
return [{
  json: {
    agent: 'none',
    action: 'unknown_intent',
    confidence: input.confidence || 0,
    result: {
      message: `Could not classify command: "${input.command}". Intent detected: ${input.intent} with confidence ${input.confidence}.`,
      suggestion: 'Please rephrase your command or specify the intent (email, calendar, research, content).'
    },
    requires_approval: false,
    routed_to: 'human_review',
    review_reason: 'unclassified_intent',
    execution_id: input.execution_id
  }
}];

// Aggregate the agent response and attach metadata
const agentResponse = $input.first().json;
const classification = $('Parse Classification').first().json;

const response = {
  orchestrator: '0000-orchestrator',
  original_command: classification.command,
  classified_intent: classification.intent,
  classification_confidence: classification.confidence,
  agent_response: agentResponse,
  confidence: agentResponse.confidence || classification.confidence,
  requires_review: false,
  completed_at: new Date().toISOString(),
  execution_id: classification.execution_id
};

// Flag for human review if confidence is below threshold
if (response.confidence < 0.7) {
  response.requires_review = true;
  response.review_reason = 'confidence_below_threshold';
}

return [{ json: response }];

